 1	import * as React from 'react';
 2	import { Chip } from '@patternfly/react-core';
 3	import { t } from 'utils/I18nUtils';
 4	
 5	interface Shortcut {
 6	  description: string;
 7	  shortcut: string;
 8	}
 9	
10	const shortcuts: Shortcut[] = [
11	  { shortcut: 'Mouse wheel', description: t('Zoom graph') },
12	  { shortcut: 'Click + Drag', description: t('Pan graph, drag node') },
13	  { shortcut: 'Shift + Drag', description: t('Select zoom area') },
14	  { shortcut: 'Ctrl + Drag', description: t('Select zoom area') },
15	  { shortcut: 'Node Click', description: t('Select node + side panel') },
16	  { shortcut: 'Edge Click', description: t('Select edge + side panel') },
17	  { shortcut: 'Right Click', description: t('Menu of options') },
18	  { shortcut: 'Menu: Node Graph', description: t('Drill into node detail graph') }
19	];
20	
21	const makeShortcut = (shortcut: Shortcut): React.ReactNode => {
22	  return (
23	    <div style={{ display: 'flex', marginBottom: '10px' }}>
24	      <div style={{ flex: '45%' }}>
25	        <Chip isReadOnly>{shortcut.shortcut}</Chip>
26	      </div>
27	
28	      <div style={{ flex: '55%' }}>{shortcut.description}</div>
29	    </div>
30	  );
31	};
32	
33	export const GraphShortcuts = (): React.ReactNode => (
34	  <>
35	    {shortcuts.map(
36	      (s: Shortcut): React.ReactNode => {
37	        return makeShortcut(s);
38	      }
39	    )}
40	  </>
41	);

